1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type ScenarioInput = { steps: { items: Item[] }[] };
3	
4	const PROCESSING_FEE = 5;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
9	const COMPONENT_BASE = 25;
10	const COMPONENT_BLOCK_BASE = 60;
11	const COMPONENT_BLOCK_SIZE = 3;
12	const ITEM_BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	};
18	
19	function policyBase(items: Item[]): number {
20	  const components: Record<string, number> = {};
21	  let base = 0;
22	  for (const item of items) {
23	    if (COMPONENT_TYPES.has(item.type)) {
24	      components[item.type] = (components[item.type] ?? 0) + 1;
25	    } else {
26	      base += ITEM_BASE_PREMIUM[item.type];
27	    }
28	  }
29	  for (const count of Object.values(components)) {
30	    base += count === COMPONENT_BLOCK_SIZE
31	      ? COMPONENT_BLOCK_BASE
32	      : count * COMPONENT_BASE;
33	  }
34	  return base;
35	}
36	
37	function curseSurcharge(items: Item[]): number {
38	  let total = 0;
39	  for (const item of items) {
40	    if (item.cursed) {
41	      total += ITEM_BASE_PREMIUM[item.type] * CURSE_SURCHARGE_RATE;
42	    }
43	  }
44	  return total;
45	}
46	
47	function highEnchantmentSurcharge(items: Item[]): number {
48	  let total = 0;
49	  for (const item of items) {
50	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
51	      total += ITEM_BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_RATE;
52	    }
53	  }
54	  return total;
55	}
56	
57	export function runScenario(input: unknown): unknown {
58	  const { steps: [{ items }] } = input as ScenarioInput;
59	  const base = policyBase(items);
60	  // First-insurance is +10% on the base; use integer tenths to avoid float drift.
61	  const withFirstInsurance = (base * 11) / 10;
62	  const premium = Math.ceil(withFirstInsurance + curseSurcharge(items) + highEnchantmentSurcharge(items)) + PROCESSING_FEE;
63	  return { results: [{ premium }] };
64	}
