function surchargeOn(
  items: Item[],
  rate: number,
  applies: (item: Item) => boolean,
): number {
  let total = 0;
  for (const item of items) {
    if (applies(item)) {
      total += ITEM_BASE_PREMIUM[item.type] * rate;
    }
  }
  return total;
}

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

export function runScenario(input: unknown): unknown {
  const { steps: [{ items }] } = input as ScenarioInput;
  const base = policyBase(items);
  // First-insurance is +10% on the base; use integer tenths to avoid float drift.
  const withFirstInsurance = (base * 11) / 10;
  const curse = surchargeOn(items, CURSE_SURCHARGE_RATE, isCursed);
  const highEnch = surchargeOn(items, HIGH_ENCHANTMENT_RATE, isHighlyEnchanted);
  const premium = Math.ceil(withFirstInsurance + curse + highEnch) + PROCESSING_FEE;
  return { results: [{ premium }] };
}
